sql:
SELECT AVG(life_expectancy) AS average_life_expectancy, year
FROM region_health_data
GROUP BY year;

SELECT AVG(air_quality_index) AS avg_air_quality_index
FROM region_environmental_data
WHERE region_id = 0;

SELECT AVG(crime_rate) AS average_crime_rate
FROM region_crime_data
WHERE year = 2023;

SELECT crime_rate, violent_crime_rate, property_crime_rate, arrest_rate
FROM region_crime_data
WHERE region_id = 0 AND year = 2020;

SELECT region_id, year, crime_rate, violent_crime_rate
FROM region_crime_data
WHERE violent_crime_rate > (
    SELECT AVG(violent_crime_rate) 
    FROM region_crime_data
);

SELECT name
FROM regions
WHERE region_status = 'Active' AND population_density > (SELECT AVG(population_density) FROM regions);

SELECT AVG(average_test_scores) AS avg_test_scores
FROM region_education_data
WHERE region_id = 0;

SELECT life_expectancy
FROM region_health_data
WHERE region_id = 0 AND year = 0;

SELECT AVG(average_house_price) AS avg_house_price
FROM region_housing_data
WHERE region_id = 1;

SELECT average_house_price, rental_price_index
FROM region_housing_data
WHERE year = 2020;

SELECT AVG(median_age) AS average_median_age, AVG(life_expectancy) AS average_life_expectancy
FROM region_demographic_data
WHERE year = 2020;

external_knowledge:
- 'most frequented regions' refers to regions with the highest number of total accesses and distinct users; 
- 'densely populated' refers to regions with a population density greater than 200; 
- 'vast' refers to regions with a geographic area greater than 1000.

- "Beacons of prosperity and longevity" refers to regions with GDP and life expectancy above the average values; 
- "Economic prowess" refers to GDP rank; 
- "Inhabitants' vitality" refers to life expectancy rank.

